(window.webpackJsonp=window.webpackJsonp||[]).push([[459],{754:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">light</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> numTimesAllBlue = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">light</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> uf=<span class=\\"hljs-built_in\\">Array</span>(light.length+<span class=\\"hljs-number\\">1</span>).fill().map(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">e,i</span>)=&gt;</span>i)\\n  <span class=\\"hljs-keyword\\">let</span> weight=<span class=\\"hljs-built_in\\">Array</span>(light.length+<span class=\\"hljs-number\\">1</span>).fill(<span class=\\"hljs-number\\">1</span>)\\n  weight[<span class=\\"hljs-number\\">0</span>]=<span class=\\"hljs-number\\">500001</span>\\n  <span class=\\"hljs-keyword\\">let</span> group=light.length+<span class=\\"hljs-number\\">1</span>\\n  <span class=\\"hljs-keyword\\">let</span> zeroGroup=<span class=\\"hljs-number\\">0</span>\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">find</span>(<span class=\\"hljs-params\\">i</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(i!==uf[i]){\\n      uf[i]=find(uf[i])\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> uf[i]\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">union</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> i=find(a),\\n      j=find(b)\\n    <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">if</span>(weight[i]&lt;weight[j]){\\n      uf[i]=j\\n      weight[j]+=weight[i]\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      uf[j]=i\\n      weight[i]+=weight[j]\\n    }\\n    group--\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">connected</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> i=find(a),\\n      j=find(b)\\n    <span class=\\"hljs-keyword\\">return</span> i===j\\n  }\\n\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;light.length;i++){\\n    union(light[i],light[i]<span class=\\"hljs-number\\">-1</span>)\\n    <span class=\\"hljs-keyword\\">if</span>(weight[<span class=\\"hljs-number\\">0</span>]<span class=\\"hljs-number\\">-500001</span> + group <span class=\\"hljs-number\\">-1</span> ===light.length){\\n      res++\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(uf,weight,group)</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  \\n\\n};\\n</code></pre>\\n"],"titleSlug":"bulb-switcher-iii","hasThinking":false,"content":"<p>\u623f\u95f4\u4e2d\u6709 <code>n</code> \u679a\u706f\u6ce1\uff0c\u7f16\u53f7\u4ece <code>1</code> \u5230 <code>n</code>\uff0c\u81ea\u5de6\u5411\u53f3\u6392\u6210\u4e00\u6392\u3002\u6700\u521d\uff0c\u6240\u6709\u7684\u706f\u90fd\u662f\u5173\u7740\u7684\u3002</p>\\n\\n<p>\u5728 <em>k</em>&nbsp; \u65f6\u523b\uff08 <em>k</em> \u7684\u53d6\u503c\u8303\u56f4\u662f <code>0</code> \u5230 <code>n - 1</code>\uff09\uff0c\u6211\u4eec\u6253\u5f00 <code>light[k]</code> \u8fd9\u4e2a\u706f\u3002</p>\\n\\n<p>\u706f\u7684\u989c\u8272\u8981\u60f3 <strong>\u53d8\u6210\u84dd\u8272</strong> \u5c31\u5fc5\u987b\u540c\u65f6\u6ee1\u8db3\u4e0b\u9762\u4e24\u4e2a\u6761\u4ef6\uff1a</p>\\n\\n<ul>\\n\\t<li>\u706f\u5904\u4e8e\u6253\u5f00\u72b6\u6001\u3002</li>\\n\\t<li>\u6392\u5728\u5b83\u4e4b\u524d\uff08\u5de6\u4fa7\uff09\u7684\u6240\u6709\u706f\u4e5f\u90fd\u5904\u4e8e\u6253\u5f00\u72b6\u6001\u3002</li>\\n</ul>\\n\\n<p>\u8bf7\u8fd4\u56de\u80fd\u591f\u8ba9 <strong>\u6240\u6709\u5f00\u7740\u7684</strong> \u706f\u90fd <strong>\u53d8\u6210\u84dd\u8272</strong> \u7684\u65f6\u523b <strong>\u6570\u76ee \u3002</strong></p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/03/08/sample_2_1725.png\\" style=\\"height: 254px; width: 575px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>light = [2,1,3,5,4]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u5f00\u7740\u7684\u706f\u90fd\u53d8\u84dd\u7684\u65f6\u523b\u5206\u522b\u662f 1\uff0c2 \u548c 4 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>light = [3,2,4,1,5]\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u5f00\u7740\u7684\u706f\u90fd\u53d8\u84dd\u7684\u65f6\u523b\u5206\u522b\u662f 3 \u548c 4\uff08index-0\uff09\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>light = [4,1,2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u5f00\u7740\u7684\u706f\u90fd\u53d8\u84dd\u7684\u65f6\u523b\u662f 3\uff08index-0\uff09\u3002\\n\u7b2c 4 \u4e2a\u706f\u5728\u65f6\u523b 3 \u53d8\u84dd\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>light = [2,1,4,3,6,5]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>light = [1,2,3,4,5,6]\\n<strong>\u8f93\u51fa\uff1a</strong>6\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n ==&nbsp;light.length</code></li>\\n\\t<li><code>1 &lt;= n &lt;= 5 * 10^4</code></li>\\n\\t<li><code>light</code> \u662f <code>[1, 2, ..., n]</code> \u7684\u4e00\u4e2a\u6392\u5217\u3002</li>\\n</ul>\\n","title":"1375. \u706f\u6ce1\u5f00\u5173 III","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1375"}')}}]);